// custom-handler.js
// Advanced handler for Node.js queue server with retry logic and exponential backoff

/**
 * Sleep utility for delay between retries
 * @param {number} ms - Milliseconds to sleep
 * @returns {Promise<void>}
 */
const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Calculate exponential backoff delay
 * @param {number} attempt - Current attempt number (1-indexed)
 * @param {number} baseDelay - Base delay in milliseconds (default: 1000ms)
 * @param {number} maxDelay - Maximum delay in milliseconds (default: 30000ms)
 * @returns {number} - Delay in milliseconds
 */
const calculateBackoffDelay = (attempt, baseDelay = 1000, maxDelay = 30000) => {
    // Exponential backoff: 1s, 2s, 4s, 8s, etc.
    const delay = Math.min(baseDelay * Math.pow(2, attempt - 1), maxDelay);
    // Add small jitter to prevent thundering herd
    const jitter = Math.random() * 200;
    return delay + jitter;
};

/**
 * Process the prompt - core logic for prompt transformation
 * @param {string} prompt - Original user prompt
 * @returns {string} - Processed prompt with system instruction if "evolve" detected
 */
const processPromptCore = (prompt) => {
    // Validate input
    if (!prompt || typeof prompt !== 'string') {
        throw new Error('Invalid prompt: prompt must be a non-empty string');
    }

    // Check for "evolve" keyword (case-insensitive)
    const hasEvolveKeyword = prompt.toLowerCase().includes('evolve');

    if (hasEvolveKeyword) {
        // Enhanced system instruction for JavaScript code generation
        const systemInstruction = `[SYSTEM INSTRUCTION]: The user's task contains the keyword "evolve". You MUST respond with complete, working JavaScript code that can be used as a custom-handler.js module for a Node.js queue server. The code must export a processTask function that takes a task object and returns a processed prompt string. Wrap your response in a \`\`\`javascript code block. The code should be self-contained and executable. Include comments explaining the logic.\n\n[USER PROMPT]: `;

        return systemInstruction + prompt;
    }

    // Return unchanged for non-evolve tasks
    return prompt;
};

/**
 * Process task with retry logic and exponential backoff
 * @param {object} task - Task object containing the prompt
 * @param {object} options - Configuration options
 * @param {number} options.maxRetries - Maximum number of retry attempts (default: 3)
 * @param {number} options.baseDelay - Base delay in milliseconds (default: 1000)
 * @param {number} options.maxDelay - Maximum delay in milliseconds (default: 30000)
 * @returns {Promise<object>} - Promise resolving to result object { success, prompt, error, attempts }
 */
const processTaskWithRetry = async (task, options = {}) => {
    const {
        maxRetries = 3,
        baseDelay = 1000,
        maxDelay = 30000
    } = options;

    let lastError = null;
    let attempts = 0;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        attempts = attempt;
        try {
            // Validate task object
            if (!task || typeof task !== 'object') {
                throw new Error('Invalid task: task must be an object');
            }

            if (!task.prompt || typeof task.prompt !== 'string') {
                throw new Error('Invalid task: missing or invalid prompt field');
            }

            // Process the prompt
            const processedPrompt = processPromptCore(task.prompt);

            // Success - return result
            return {
                success: true,
                prompt: processedPrompt,
                error: null,
                attempts: attempts,
                originalPrompt: task.prompt,
                retriesUsed: attempt - 1
            };

        } catch (error) {
            lastError = error;

            // Log the error (could be replaced with proper logger)
            console.error(`Attempt ${attempt}/${maxRetries} failed:`, error.message);

            // If this was the last attempt, break and return error
            if (attempt === maxRetries) {
                break;
            }

            // Calculate backoff delay and wait before retry
            const delay = calculateBackoffDelay(attempt, baseDelay, maxDelay);
            console.log(`Retrying in ${Math.round(delay)}ms... (attempt ${attempt + 1}/${maxRetries})`);
            await sleep(delay);
        }
    }

    // All retries exhausted - return error result
    return {
        success: false,
        prompt: null,
        error: lastError,
        attempts: attempts,
        originalPrompt: task?.prompt || null,
        retriesUsed: maxRetries
    };
};

/**
 * Main exported function for queue server
 * @param {object} task - Task object containing { prompt: string, ...otherFields }
 * @returns {Promise<string>} - Processed prompt string
 * @throws {Error} - If processing fails after all retries
 */
const processTask = async (task) => {
    // Configuration can be read from environment variables or task metadata
    const config = {
        maxRetries: task.retryConfig?.maxRetries || process.env.CUSTOM_HANDLER_MAX_RETRIES || 3,
        baseDelay: task.retryConfig?.baseDelay || process.env.CUSTOM_HANDLER_BASE_DELAY || 1000,
        maxDelay: task.retryConfig?.maxDelay || process.env.CUSTOM_HANDLER_MAX_DELAY || 30000
    };

    // Process with retry logic
    const result = await processTaskWithRetry(task, config);

    // If successful, return the processed prompt
    if (result.success) {
        return result.prompt;
    }

    // If failed after all retries, throw error with details
    throw new Error(
        `Failed to process task after ${result.attempts} attempts. ` +
        `Last error: ${result.error?.message || 'Unknown error'}`
    );
};

// Export the main function and utilities for testing/extensibility
module.exports = {
    processTask,           // Main exported function for queue server
    processPromptCore,     // Exposed for unit testing
    processTaskWithRetry,  // Exposed for advanced usage
    calculateBackoffDelay, // Exposed for testing
    sleep                 // Exposed for testing
};

