/**
 * Wait for an element to appear in DOM with timeout
 * @param {string|string[]} selectors - CSS selector or array of selectors
 * @param {number} timeout - Timeout in milliseconds
 * @param {Element} context - Context element to search within (default: document)
 * @returns {Promise<Element>} - Found element
 * @throws {Error} - If element not found within timeout
 */
const waitForElement = async (selectors, timeout = CONFIG.FIND_ELEMENT_TIMEOUT, context = document) => {
    const selectorArray = Array.isArray(selectors) ? selectors : [selectors];
    const startTime = Date.now();

    while (Date.now() - startTime < timeout) {
        for (const selector of selectorArray) {
            const element = context.querySelector(selector);
            if (element && element.isConnected) {
                console.log(`[ChromeVideo] Element found with selector: ${selector}`);
                return element;
            }
        }
        await wait(CONFIG.ELEMENT_POLL_INTERVAL);
    }

    // Build error message with attempted selectors
    throw new Error(`Element not found within ${timeout}ms. Attempted selectors: ${selectorArray.join(', ')}`);
};

