            if (button) {
                console.log(`[ChromeVideo] Send button found using strategy ${i + 1}`);
                return button;
            }
        } catch (error) {
            console.warn(`[ChromeVideo] Strategy ${i + 1} failed:`, error.message);
        }
    }

