/**
 * Simple logging utility with timestamps
 */
const Logger = {
    /**
     * Get current timestamp in ISO format with milliseconds
     * @returns {string} Formatted timestamp
     */
    getTimestamp: () => {
        const now = new Date();
        return now.toISOString();
    },

    /**
     * Get formatted timestamp for human readability
     * @returns {string} Human-readable timestamp
     */
    getHumanTimestamp: () => {
        const now = new Date();
        return now.toLocaleString('en-US', {
            year: 'numeric',
            month: '2-digit',
            day: '2-digit',
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit',
            hour12: false
        });
    },

    /**
     * Log task prompt before processing
     * @param {object} task - The task object being processed
     * @param {string} stage - Processing stage ('before' or 'after')
     * @param {object} metadata - Additional metadata to log
     */
    logTask: (task, stage = 'before', metadata = {}) => {
        const timestamp = Logger.getTimestamp();
        const humanTime = Logger.getHumanTimestamp();

        // Extract task ID or generate one
        const taskId = task.id || task.taskId || `task_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

        // Get prompt preview (first 100 characters)
        const promptPreview = task.prompt ? 
            (task.prompt.length > 100 ? task.prompt.substring(0, 100) + '...' : task.prompt) : 
            'undefined';

        // Create log entry
        const logEntry = {
            timestamp: timestamp,
            humanTime: humanTime,
            stage: stage,
            taskId: taskId,
            promptLength: task.prompt ? task.prompt.length : 0,
            promptPreview: promptPreview,
            hasEvolveKeyword: task.prompt ? task.prompt.toLowerCase().includes('evolve') : false,
            ...metadata
        };

        // Log to console with colors (if supported)
        const logColor = stage === 'before' ? '\x1b[36m' : '\x1b[32m'; // Cyan for before, green for after
        const resetColor = '\x1b[0m';

        console.log(`${logColor}[${humanTime}] [${stage.toUpperCase()}] Task ${taskId}:${resetColor}`);
        console.log(`  Prompt Length: ${logEntry.promptLength} chars`);
        console.log(`  Prompt Preview: "${logEntry.promptPreview}"`);
        console.log(`  Contains 'evolve': ${logEntry.hasEvolveKeyword}`);

        if (Object.keys(metadata).length > 0) {
            console.log(`  Metadata:`, metadata);
        }

        // Also log as JSON for structured logging (useful for log aggregation)
        console.log(`  JSON: ${JSON.stringify(logEntry)}`);
        console.log('-'.repeat(80));

        return logEntry;
    },

    /**
     * Log error with timestamp
     * @param {object} task - The task that caused error
     * @param {Error} error - The error object
     * @param {number} attempt - Attempt number if retrying
     */
    logError: (task, error, attempt = null) => {
        const timestamp = Logger.getTimestamp();
        const humanTime = Logger.getHumanTimestamp();
        const taskId = task.id || task.taskId || 'unknown';

        const errorLog = {
            timestamp: timestamp,
            humanTime: humanTime,
            taskId: taskId,
            error: error.message,
